import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import { VideoCard } from "../Cinema/VideoCard";
import "./NewReservation.css";

function NewReservation() {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCinema, setSelectedCinema] = useState(null);
  const [selectedMovie, setSelectedMovie] = useState(null);
  const [selectedSlots, setSelectedSlots] = useState([]);
  const [selectedWeek, setSelectedWeek] = useState(null);
  const [currentStep, setCurrentStep] = useState(1);
  const [customerInfo, setCustomerInfo] = useState({
    customer_name: '',
    customer_email: '',
    customer_phone: '',
    company_name: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Fetch cinemas from API
  useEffect(() => {
    const fetchCinemas = async () => {
      try {
        console.log('Fetching cinemas...');
        setLoading(true);
        const response = await fetch('http://localhost:5000/api/cinemas');
        const data = await response.json();
        
        if (data.success) {
          console.log('Cinemas loaded:', data.data.length);
          setCinemas(data.data);
        } else {
          console.error('Error fetching cinemas:', data.message);
        }
      } catch (error) {
        console.error('Error fetching cinemas:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchCinemas();
  }, []);

  // Helper function to get week start and end dates
  const getWeekDates = (startDate) => {
    const start = new Date(startDate);
    const end = new Date(start);
    end.setDate(start.getDate() + 6);
    return { start, end };
  };

  // Helper function to format date
  const formatDate = (date) => {
    return new Date(date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  // Helper function to check if a movie is available for the selected week
  const isMovieAvailableForWeek = (movie, weekStart, weekEnd) => {
    if (!movie.start_date || !movie.end_date) return false;
    
    const movieStart = new Date(movie.start_date);
    const movieEnd = new Date(movie.end_date);
    
    // Movie should NOT be showing during the selected week
    return !(movieStart <= weekEnd && movieEnd >= weekStart);
  };

  const handleCinemaSelect = (cinema) => {
    setSelectedCinema(cinema);
    setSelectedMovie(null);
    setSelectedSlots([]);
    setSelectedWeek(null);
    setCurrentStep(2);
  };

  const handleWeekSelect = (weekStartDate) => {
    const weekDates = getWeekDates(weekStartDate);
    setSelectedWeek(weekDates);
    setCurrentStep(3);
  };

  const handleMovieSelect = (movie, movieKey) => {
    if (!selectedWeek) {
      alert('Please select a week first');
      return;
    }

    // Check if movie is available for selected week
    if (!isMovieAvailableForWeek(movie, selectedWeek.start, selectedWeek.end)) {
      alert('This movie is showing during the selected week. Please choose a different week or movie.');
      return;
    }

    setSelectedMovie({ ...movie, movieKey });
    setSelectedSlots([]);
    setCurrentStep(4);
  };

  const handleSlotSelect = (slot) => {
    const slotId = `${slot.slot_type}_${slot.slot_number}`;
    const isSelected = selectedSlots.some(s => s.slot_id === slotId);
    
    if (isSelected) {
      setSelectedSlots(selectedSlots.filter(s => s.slot_id !== slotId));
    } else {
      setSelectedSlots([...selectedSlots, {
        slot_id: slotId,
        slot_type: slot.slot_type,
        slot_number: slot.slot_number,
        price: slot.price
      }]);
    }
  };

  const calculateTotal = () => {
    return selectedSlots.reduce((total, slot) => total + slot.price, 0);
  };

  const getAvailableSlots = () => {
    if (!selectedCinema || !selectedMovie) return [];
    
    const moviePricing = selectedCinema.movie_slot_pricing[selectedMovie.movieKey];
    if (!moviePricing || !moviePricing.slots) return [];
    
    return moviePricing.slots;
  };

  const getSlotPricingInfo = (movieKey) => {
    if (!selectedCinema || !selectedCinema.movie_slot_pricing[movieKey]) {
      return null;
    }
    
    const pricing = selectedCinema.movie_slot_pricing[movieKey];
    const startingSlots = pricing.slots.filter(s => s.slot_type === 'starting').length;
    const intervalSlots = pricing.slots.filter(s => s.slot_type === 'interval').length;
    const endingSlots = pricing.slots.filter(s => s.slot_type === 'ending').length;
    
    return {
      starting: { price: pricing.starting_price, count: startingSlots },
      interval: { price: pricing.interval_price, count: intervalSlots },
      ending: { price: pricing.ending_price, count: endingSlots }
    };
  };

  const handleSubmit = async () => {
    if (!selectedCinema || !selectedMovie || !selectedSlots.length || !selectedWeek) {
      alert('Please complete all required fields');
      return;
    }

    setIsSubmitting(true);
    
    try {
      const reservationData = {
        cinema_id: selectedCinema._id,
        movie_name: selectedMovie.name,
        movie_key: selectedMovie.movieKey,
        week_start_date: selectedWeek.start.toISOString(),
        week_end_date: selectedWeek.end.toISOString(),
        advertisement_slots: selectedSlots,
        advertisement_duration: 30, // Default duration
        customer_name: customerInfo.customer_name,
        customer_email: customerInfo.customer_email,
        customer_phone: customerInfo.customer_phone,
        company_name: customerInfo.company_name,
        notes: `Weekly reservation for ${formatDate(selectedWeek.start)} - ${formatDate(selectedWeek.end)}`
      };

      console.log('Submitting reservation:', reservationData);

      const response = await fetch('http://localhost:5000/api/reservations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(reservationData)
      });

      const result = await response.json();
      
      if (result.success) {
        alert('Reservation created successfully!');
        // Reset form
        setSelectedCinema(null);
        setSelectedMovie(null);
        setSelectedSlots([]);
        setSelectedWeek(null);
        setCurrentStep(1);
        setCustomerInfo({
          customer_name: '',
          customer_email: '',
          customer_phone: '',
          company_name: ''
        });
      } else {
        alert('Error creating reservation: ' + result.message);
      }
    } catch (error) {
      console.error('Error creating reservation:', error);
      alert('Error creating reservation. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStep1 = () => (
    <div className="step-content">
      <h2>Select Cinema</h2>
      <div className="cinema-table">
        <table>
          <thead>
            <tr>
              <th>Cinema Name</th>
              <th>Location</th>
              <th>Contact</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {cinemas.map((cinema) => (
              <tr key={cinema._id}>
                <td>{cinema.cinema_name}</td>
                <td>{cinema.cinema_location}</td>
                <td>{cinema.contact_info?.phone || 'N/A'}</td>
                <td>
                  <button 
                    className="select-cinema-btn"
                    onClick={() => handleCinemaSelect(cinema)}
                  >
                    Select This Cinema
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderStep2 = () => (
    <div className="step-content">
      <h2>Select Week for Advertisement</h2>
      <div className="selected-cinema-info">
        <h3>{selectedCinema.cinema_name}</h3>
        <p>{selectedCinema.cinema_location}</p>
      </div>
      
      <div className="week-selection">
        <h3>Choose Your Advertisement Week</h3>
        <p>Select a week when you want your advertisement to run. Movies showing during this week will not be available for selection.</p>
        
        <div className="week-options">
          {Array.from({ length: 8 }, (_, i) => {
            const weekStart = new Date();
            weekStart.setDate(weekStart.getDate() + (i * 7));
            weekStart.setHours(0, 0, 0, 0);
            
            const weekEnd = new Date(weekStart);
            weekEnd.setDate(weekStart.getDate() + 6);
            weekEnd.setHours(23, 59, 59, 999);
            
            return (
              <div key={i} className="week-option" onClick={() => handleWeekSelect(weekStart)}>
                <div className="week-label">
                  {i === 0 ? 'This Week' : i === 1 ? 'Next Week' : `Week ${i + 1}`}
                </div>
                <div className="week-dates">
                  {formatDate(weekStart)} - {formatDate(weekEnd)}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );

  const renderStep3 = () => (
    <div className="step-content">
      <h2>Select Movie</h2>
      <div className="selected-cinema-info">
        <h3>{selectedCinema.cinema_name}</h3>
        <p>{selectedCinema.cinema_location}</p>
        <p><strong>Selected Week:</strong> {formatDate(selectedWeek.start)} - {formatDate(selectedWeek.end)}</p>
      </div>
      
      <div className="movies-list">
        {Object.entries(selectedCinema.ongoing_movies).map(([movieKey, movie]) => {
          if (!movie.name) return null;
          
          const isAvailable = isMovieAvailableForWeek(movie, selectedWeek.start, selectedWeek.end);
          const pricingInfo = getSlotPricingInfo(movieKey);
          
          return (
            <div key={movieKey} className={`video-card ${!isAvailable ? 'unavailable' : ''}`}>
              <div className="video-thumbnail" onClick={() => handleTrailerClick(movie.trailer_link)}>
                <img src={getYouTubeThumbnail(movie.trailer_link)} alt={movie.name} />
                <div className="play-button">
                  <i className="fa fa-play"></i>
                </div>
                {!isAvailable && (
                  <div className="unavailable-overlay">
                    <span>Not Available This Week</span>
                  </div>
                )}
              </div>
              
              <div className="video-content">
                <h3>{movie.name}</h3>
                <div className="movie-dates">
                  <span className="date-badge">
                    {formatDate(movie.start_date)} - {formatDate(movie.end_date)}
                  </span>
                </div>
                
                {pricingInfo && (
                  <div className="slot-pricing-info">
                    <div className="slot-categories">
                      <div className="slot-category-info">
                        <span className="slot-type">Starting:</span>
                        <span className="slot-details">₹{pricingInfo.starting.price} ({pricingInfo.starting.count} slots)</span>
                      </div>
                      <div className="slot-category-info">
                        <span className="slot-type">Interval:</span>
                        <span className="slot-details">₹{pricingInfo.interval.price} ({pricingInfo.interval.count} slots)</span>
                      </div>
                      <div className="slot-category-info">
                        <span className="slot-type">Ending:</span>
                        <span className="slot-details">₹{pricingInfo.ending.price} ({pricingInfo.ending.count} slots)</span>
                      </div>
                    </div>
                  </div>
                )}
                
                <button 
                  className="select-movie-btn"
                  onClick={() => handleMovieSelect(movie, movieKey)}
                  disabled={!isAvailable}
                >
                  {isAvailable ? 'Select This Movie' : 'Not Available This Week'}
                </button>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );

  const renderStep4 = () => (
    <div className="step-content">
      <h2>Select Advertisement Slots</h2>
      <div className="selected-cinema-info">
        <h3>{selectedCinema.cinema_name}</h3>
        <p>{selectedCinema.cinema_location}</p>
        <p><strong>Movie:</strong> {selectedMovie.name}</p>
        <p><strong>Week:</strong> {formatDate(selectedWeek.start)} - {formatDate(selectedWeek.end)}</p>
      </div>
      
      <div className="compact-slots-selection">
        <div className="slot-cards">
          {['starting', 'interval', 'ending'].map(slotType => {
            const slots = getAvailableSlots().filter(slot => slot.slot_type === slotType);
            const pricing = getSlotPricingInfo(selectedMovie.movieKey);
            
            return (
              <div key={slotType} className="slot-card">
                <div className="slot-card-header">
                  <h3>{slotType.charAt(0).toUpperCase() + slotType.slice(1)} Slots</h3>
                  <div className="slot-count">
                    {slots.length} available
                  </div>
                </div>
                <div className="slot-card-content">
                  {slots.map(slot => (
                    <div 
                      key={`${slot.slot_type}_${slot.slot_number}`}
                      className={`compact-slot-item ${selectedSlots.some(s => s.slot_id === `${slot.slot_type}_${slot.slot_number}`) ? 'selected' : ''}`}
                      onClick={() => handleSlotSelect(slot)}
                    >
                      <span className="slot-number">Slot {slot.slot_number}</span>
                      <span className="slot-price">₹{slot.price}</span>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
        
        <div className="total-summary">
          <div className="total-amount">
            Total: ₹{calculateTotal()}
          </div>
        </div>
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="step-content">
      <h2>Customer Information & Confirmation</h2>
      
      <div className="selected-slots-details">
        <h3>Reservation Summary</h3>
        <div className="summary-item">
          <strong>Cinema:</strong> {selectedCinema.cinema_name}
        </div>
        <div className="summary-item">
          <strong>Location:</strong> {selectedCinema.cinema_location}
        </div>
        <div className="summary-item">
          <strong>Movie:</strong> {selectedMovie.name}
        </div>
        <div className="summary-item">
          <strong>Week:</strong> {formatDate(selectedWeek.start)} - {formatDate(selectedWeek.end)}
        </div>
        <div className="summary-item">
          <strong>Selected Slots:</strong> {selectedSlots.length} slots
        </div>
        <div className="summary-item">
          <strong>Total Amount:</strong> ₹{calculateTotal()}
        </div>
      </div>
      
      <div className="customer-info-form">
        <h3>Your Information</h3>
        <div className="form-row">
          <div className="form-group">
            <label>Full Name *</label>
            <input 
              type="text" 
              value={customerInfo.customer_name}
              onChange={(e) => setCustomerInfo({...customerInfo, customer_name: e.target.value})}
              required
            />
          </div>
          <div className="form-group">
            <label>Email *</label>
            <input 
              type="email" 
              value={customerInfo.customer_email}
              onChange={(e) => setCustomerInfo({...customerInfo, customer_email: e.target.value})}
              required
            />
          </div>
        </div>
        <div className="form-row">
          <div className="form-group">
            <label>Phone Number *</label>
            <input 
              type="tel" 
              value={customerInfo.customer_phone}
              onChange={(e) => setCustomerInfo({...customerInfo, customer_phone: e.target.value})}
              required
            />
          </div>
          <div className="form-group">
            <label>Company Name *</label>
            <input 
              type="text" 
              value={customerInfo.company_name}
              onChange={(e) => setCustomerInfo({...customerInfo, company_name: e.target.value})}
              required
            />
          </div>
        </div>
      </div>
      
      <div className="confirmation-actions">
        <button 
          className="btn-confirm"
          onClick={handleSubmit}
          disabled={isSubmitting}
        >
          {isSubmitting ? 'Creating Reservation...' : 'Confirm Reservation'}
        </button>
      </div>
    </div>
  );

  // Helper functions for YouTube integration
  const getYouTubeVideoId = (url) => {
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const getYouTubeThumbnail = (url) => {
    const videoId = getYouTubeVideoId(url);
    if (videoId) {
      return `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;
    }
    return '/img/placeholder-video.jpg';
  };

  const handleTrailerClick = (url) => {
    if (url) {
      window.open(url, '_blank');
    }
  };

  const renderCurrentStep = () => {
    switch (currentStep) {
      case 1: return renderStep1();
      case 2: return renderStep2();
      case 3: return renderStep3();
      case 4: return renderStep4();
      case 5: return renderStep5();
      default: return renderStep1();
    }
  };

  const nextStep = () => {
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  const prevStep = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  return (
    <div>
      <Nav />
      
      <section className="hero">
        <div className="hero-content">
          <h1>Make a Reservation</h1>
          <p>Book your cinema advertisement slots</p>
        </div>
      </section>

      <section className="reservation-section">
        <div className="container">
          <div className="step-indicator">
            <div className="steps-row">
              <div className={`step ${currentStep >= 1 ? 'active' : ''}`}>
                <div className="step-number">1</div>
                <div className="step-label">Cinema</div>
              </div>
              <div className={`step ${currentStep >= 2 ? 'active' : ''}`}>
                <div className="step-number">2</div>
                <div className="step-label">Week</div>
              </div>
              <div className={`step ${currentStep >= 3 ? 'active' : ''}`}>
                <div className="step-number">3</div>
                <div className="step-label">Movie</div>
              </div>
              <div className={`step ${currentStep >= 4 ? 'active' : ''}`}>
                <div className="step-number">4</div>
                <div className="step-label">Slots</div>
              </div>
              <div className={`step ${currentStep >= 5 ? 'active' : ''}`}>
                <div className="step-number">5</div>
                <div className="step-label">Confirm</div>
              </div>
            </div>
          </div>

          {loading ? (
            <div className="loading">Loading cinemas...</div>
          ) : (
            <>
              {renderCurrentStep()}
              
              <div className="step-navigation">
                {currentStep > 1 && (
                  <button className="btn-secondary" onClick={prevStep}>
                    Previous
                  </button>
                )}
                {currentStep < 5 && currentStep !== 2 && (
                  <button className="btn-primary" onClick={nextStep}>
                    Next
                  </button>
                )}
              </div>
            </>
          )}
        </div>
      </section>
    </div>
  );
}

export default NewReservation;
